settings.css:
.annual_rich_text .rich-text__blocks{max-width:100%;}

.annual_rich_text .custom_block_row{display:flex;gap:30px;max-width: 800px;
margin: 20px 0;flex-wrap:wrap;}

.annual_rich_text .custom_block{width:calc(50% - 15px);background-color:#01a10b;color:#fff;padding:25px;font-weight:600;text-align:center;display:flex;align-items:center;justify-content:center;}

.annual_rich_text .custom_html{padding: 40px;display: flex;flex-direction: column;justify-content: center;background: #d1fff4;color: #000;text-align:center;align-items:center}

.annual_rich_text .rich-text__html li ul{list-style:disc;}

.annual_rich_text .rich-text__html li ul li:marker{color:#01a10b;}

@media screen and (max-width:991px){
.annual_banner_section .hero_banner_description{font-size:22px;line-height:30px}
}

@media screen and (max-width:768px){
.annual_banner_section .hero_banner_description{font-size:18px;line-height:26px}
}

@media screen and (max-width:575px){
.annual_rich_text .custom_block{width:100%;
}

.annual_btm_text .cust_img_txt{}

.annual_btm_text .cust_img_txt_block{display: flex;}

.annual_btm_text .cust_img_txt_block figure{margin:0;display:flex;align-items:center;width:50%;padding:20px 30px}

.annual_btm_text .cust_img_txt_block img{border:0;object-fit:contain;max-height: 80px;}

.annual_btm_text .cust_img_txt_block div{text-align: left;display: flex;align-items: center;width:50%; padding:20px 30px;font-size: 18px;line-height: 26px;color: #193f97;font-weight: 700;}

@media screen and (max-width: 991px){
.annual_btm_text .rich-text__blocks {max-width: 100%;}
}

@media screen and (max-width: 768px){
.annual_btm_text .cust_img_txt_block figure{padding:15px;}

.annual_btm_text .cust_img_txt_block div{padding:15px;font-size:16px;}
}

@media screen and (max-width: 575px){
.annual_btm_text .cust_img_txt_block{flex-direction : column-reverse;margin:40px 0;}

.annual_btm_text .cust_img_txt_block figure{width:100%;padding:0;justify-content:center}

.annual_btm_text .cust_img_txt_block div{width:100%;padding:0 0 10px;text-align:center;display:block;}

}
